public class deliverablesController {
   public Session__c thisSession {get; set;}

  // Constructor
 public deliverablesController(ApexPages.StandardController controller) {
  this.proj = (Session__c)controller.getSubject();

     this.delivers = [ SELECT 
      d.SystemModstamp, d.Name, 
      d.Session__c, d.Student_Name__c, d.Attendance_Date__c, d.Present__c, 
      d.Absent__c, d.Excuse_Details__c, d.Tardy__c, d.Tardy_Notes__c, d.Type__c,Student_Phone__c,Student_Email__c 
      FROM 
      Attendance__c d 
      WHERE 
      d.Session__c= :proj.id order by Student_Last_Name__c ];
      thisSession = proj;

       }

 // Action Method called from page button
 public pagereference save() {
  try {
      upsert this.delivers;
      PageReference parentPage = new PageReference('/' + thisSession.Id);
      parentPage.setRedirect(true);
      return parentPage;
  } catch(Exception e) {
      ApexPages.addMessages(e);
      return null;
  }

 }

 // Action Method called from page link
 public pagereference newDeliverable() { 
  Attendance__c d = new Attendance__c ();
  d.Session__c=this.proj.id; 
  delivers.add( d );
  return null;
 }

 // public Getter to provide table headers 
 public string[] getheaders() { return new string [] 
  {'Attendance ID','Type','Name','Phone','Email','Attendance Date','Present', 'Absent','Excuse Details','Tardy','Tardy Notes'} ; }

 // public Getter to list project deliverables
 public Attendance__c [] getDeliverables() { 
  return this.delivers; 
 } 

 // class variables
 Session__c proj;
 Attendance__c [] delivers; 
}

